mapper.select:
SELECT b.id, b.user_id AS userId, u.nickname, b.title, b.content, start_date AS startDate, end_date AS endDate, b.hit, b.like_count AS likeCount, (SELECT COUNT(*) FROM Comments WHERE board_id = b.id) AS commentCount, b.region, b.created_at AS createdAt FROM Boards b JOIN Users u ON b.user_id = u.id
b.region = #{region}
AND b.user_id = #{filterUserId}
AND b.id IN ( SELECT bh.board_id FROM board_hashtag bh JOIN Hashtag h ON bh.hashtag_id = h.id WHERE h.tag_name IN
#{tagName}
)
ORDER BY b.like_count DESC, b.id DESC
ORDER BY b.hit DESC, b.id DESC
ORDER BY b.id DESC

mapper.update:
UPDATE Boards 
SET hit = hit + 1 
WHERE id = #{id}

UPDATE Boards
SET like_count = GREATEST(0, like_count + #{amount})
WHERE id = #{boardId}

mapper.select:
SELECT id, user_id AS userId, plan_id AS planId, title, content, start_date, end_date, hit, created_at AS createdAt, like_count AS likeCount, region
FROM Boards
WHERE id = #{id}
